# EngineError
# We want to define each variant as a nested class that's also a subclass,
# which is tricky in Python.  To accomplish this we're going to create each
# class separately, then manually add the child classes to the base class's
# __dict__.  All of this happens in dummy class to avoid polluting the module
# namespace.
class EngineError(Exception):
    """
    Errors surfaced across the FFI boundary.
    """

    pass

_UniffiTempEngineError = EngineError

class EngineError:  # type: ignore
    """
    Errors surfaced across the FFI boundary.
    """

    class InvalidRuleset(_UniffiTempEngineError):
        """
        `from_ruleset_json` was given a ruleset that didn't parse.
        """

        def __init__(self, message):
            super().__init__(", ".join([
                "message={!r}".format(message),
            ]))
            self.message = message

        def __repr__(self):
            return "EngineError.InvalidRuleset({})".format(str(self))
    _UniffiTempEngineError.InvalidRuleset = InvalidRuleset # type: ignore

EngineError = _UniffiTempEngineError # type: ignore
del _UniffiTempEngineError


class _UniffiConverterTypeEngineError(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        variant = buf.read_i32()
        if variant == 1:
            return EngineError.InvalidRuleset(
                _UniffiConverterString.read(buf),
            )
        raise InternalError("Raw enum value doesn't match any cases")

    @staticmethod
    def check_lower(value):
        if isinstance(value, EngineError.InvalidRuleset):
            _UniffiConverterString.check_lower(value.message)
            return

    @staticmethod
    def write(value, buf):
        if isinstance(value, EngineError.InvalidRuleset):
            buf.write_i32(1)
            _UniffiConverterString.write(value.message, buf)





class Qualifier(enum.Enum):
    """
    Canonical spatial qualifier (the richer Flutter `LocationQualifier` set).
    The Android binding folds `CloseTo`→Near and `InArea`→In to match its
    4-value `PlaceQualifier`; the UI turns these into localized words.
    """

    ON = 0
    """
    Standing on the feature (peak / glacier / island).
    """

    
    CLOSE_TO = 1
    """
    Near but outside a point feature (loose peak / farm / water).
    """

    
    AT_PLACE = 2
    """
    Touching a water body or building.
    """

    
    IN_AREA = 3
    """
    Inside a bounded area (settlement / park).
    """

    
    NEAR = 4
    """
    In the wider periphery of a feature.
    """

    


class _UniffiConverterTypeQualifier(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        variant = buf.read_i32()
        if variant == 1:
            return Qualifier.ON
        if variant == 2:
            return Qualifier.CLOSE_TO
        if variant == 3:
            return Qualifier.AT_PLACE
        if variant == 4:
            return Qualifier.IN_AREA
        if variant == 5:
            return Qualifier.NEAR
        raise InternalError("Raw enum value doesn't match any cases")

    @staticmethod
    def check_lower(value):
        if value == Qualifier.ON:
            return
        if value == Qualifier.CLOSE_TO:
            return
        if value == Qualifier.AT_PLACE:
            return
        if value == Qualifier.IN_AREA:
            return
        if value == Qualifier.NEAR:
            return
        raise ValueError(value)

    @staticmethod
    def write(value, buf):
        if value == Qualifier.ON:
            buf.write_i32(1)
        if value == Qualifier.CLOSE_TO:
            buf.write_i32(2)
        if value == Qualifier.AT_PLACE:
            buf.write_i32(3)
        if value == Qualifier.IN_AREA:
            buf.write_i32(4)
        if value == Qualifier.NEAR:
            buf.write_i32(5)





class _UniffiConverterOptionalDouble(_UniffiConverterRustBuffer):
    @classmethod
    def check_lower(cls, value):
        if value is not None:
            _UniffiConverterDouble.check_lower(value)

    @classmethod
    def write(cls, value, buf):
        if value is None:
            buf.write_u8(0)
            return

        buf.write_u8(1)
        _UniffiConverterDouble.write(value, buf)

    @classmethod
    def read(cls, buf):
        flag = buf.read_u8()
        if flag == 0:
            return None
        elif flag == 1:
            return _UniffiConverterDouble.read(buf)
        else:
            raise InternalError("Unexpected flag byte for optional type")



